const QUESTIONS_ISSAP_C2 = [
  { id:50301, domain:3, level:3, question:"Which property distinguishes symmetric encryption from asymmetric encryption in a security architecture?", options:["It always relies on a public and private key pair for every operation","It uses one shared secret key for both encryption and decryption operations","It can never be used to protect data confidentiality at rest reliably","It inherently provides non-repudiation without any additional controls"], correct:1, explanation:"Symmetric ciphers use a single shared key for both directions; asymmetric uses a key pair. Symmetric alone does not provide non-repudiation." },
  { id:50302, domain:3, level:3, question:"An architect needs to encrypt large bulk data streams efficiently while exchanging the key securely over an untrusted channel. What hybrid approach fits best?", options:["Use a symmetric cipher for bulk data and asymmetric to exchange the key","Use RSA to encrypt all the bulk data and skip any symmetric step across environments","Use only hashing to protect the bulk data confidentiality in transit","Use a static shared password embedded in the application source code"], correct:0, explanation:"Hybrid cryptosystems use fast symmetric encryption for bulk data and asymmetric to securely exchange the symmetric key. Hashing offers no confidentiality." },
  { id:50303, domain:3, level:3, question:"What best describes the difference between a block cipher and a stream cipher?", options:["A block cipher processes data one continuous bit or byte stream at a time under typical conditions","A stream cipher encrypts fixed-size groups of bits in discrete rounds for this purpose","Both always require an initialization vector of identical fixed length to operate","A block cipher encrypts fixed-size data blocks while a stream cipher works bit by bit"], correct:3, explanation:"Block ciphers operate on fixed-size blocks; stream ciphers encrypt continuously bit/byte at a time. Not all stream ciphers require an IV of the same length." },
  { id:50304, domain:3, level:2, question:"Which AES mode provides both confidentiality and built-in authentication of the ciphertext in one operation?", options:["Cipher Block Chaining mode using a random initialization vector value","Electronic Codebook mode encrypting each block independently of others","Galois/Counter Mode producing both ciphertext and an authentication tag","Counter mode alone without any accompanying message authentication code"], correct:2, explanation:"GCM is an authenticated encryption mode producing a tag. CBC and CTR alone provide only confidentiality and need a separate MAC; ECB is insecure." },
  { id:50305, domain:3, level:3, question:"Why is AES Electronic Codebook (ECB) mode generally avoided in modern architectures?", options:["It is far too slow to be practical for any real production workload","Identical plaintext blocks produce identical ciphertext, leaking patterns","It requires a separate hardware security module for every single block","It cannot be implemented in software and needs specialized AES chips"], correct:1, explanation:"ECB encrypts identical blocks to identical ciphertext, revealing data patterns. It is not inherently slow nor hardware-dependent." },
  { id:50306, domain:3, level:3, question:"ChaCha20-Poly1305 is often selected over AES-GCM in which architectural scenario?", options:["Software-only or mobile platforms lacking AES hardware acceleration","Environments with hardware AES acceleration available on every endpoint","Systems that require an insecure but extremely fast legacy cipher","Cases where only message integrity and no confidentiality is needed"], correct:0, explanation:"ChaCha20-Poly1305 performs well in software without AES hardware, common on mobile. Where AES-NI exists, AES-GCM is often preferred." },
  { id:50307, domain:3, level:1, question:"What is the primary security service provided by a cryptographic hash function?", options:["Confidentiality by reversibly transforming plaintext into ciphertext","Non-repudiation by binding a private key to a verified identity","Key exchange by deriving a shared secret over a public channel for this purpose","Integrity by producing a fixed-size fingerprint that detects changes"], correct:3, explanation:"Hashes provide integrity via a fixed fingerprint; they are one-way and offer no confidentiality, key exchange, or by themselves non-repudiation." },
  { id:50308, domain:3, level:2, question:"Why does HMAC provide stronger message authentication than simply hashing the message concatenated with a key?", options:["HMAC encrypts the message so confidentiality is also fully guaranteed","HMAC eliminates the need for any shared secret between the parties by design","HMAC uses a nested keyed construction resistant to length-extension attacks","HMAC replaces the hash with an asymmetric digital signature internally"], correct:2, explanation:"HMAC's nested keyed structure resists length-extension attacks that naive hash(key||message) suffers. HMAC provides integrity/authenticity, not confidentiality." },
  { id:50309, domain:3, level:3, question:"Which statement correctly contrasts SHA-2 and SHA-3 for an architect choosing a hash?", options:["SHA-3 is a Merkle-Damgard design while SHA-2 uses the sponge construction","SHA-3 uses a sponge construction differing structurally from SHA-2's design","SHA-2 has been formally broken and must be replaced immediately by SHA-3","Both are stream ciphers and therefore unsuitable for hashing any data"], correct:1, explanation:"SHA-3 uses the Keccak sponge construction; SHA-2 uses Merkle-Damgard. SHA-2 remains secure, so SHA-3 is an alternative, not a forced replacement." },
  { id:50310, domain:3, level:1, question:"What does a digital signature primarily provide that a plain MAC does not?", options:["Non-repudiation, since only the signer's private key could create it","Faster verification because signatures use only symmetric operations","Confidentiality of the signed message contents during transmission","Automatic key rotation each time the message is signed and sent across environments"], correct:0, explanation:"Digital signatures use the signer's private key, providing non-repudiation. MACs use a shared key so either party could create them, preventing non-repudiation." },
  { id:50311, domain:3, level:2, question:"In a typical digital signature scheme, what is actually encrypted with the signer's private key?", options:["The entire plaintext message regardless of how large it happens to be","A hash digest of the message, which is far smaller and fixed in size","The recipient's public key to authenticate the receiving endpoint","A random symmetric session key shared between sender and receiver"], correct:1, explanation:"Signing transforms a hash of the message with the private key for efficiency; signing the whole large message directly would be impractical." },
  { id:50312, domain:3, level:2, question:"In a PKI hierarchy, what is the role of the root certificate authority?", options:["It issues all end-entity certificates directly to every user device","It maintains the real-time OCSP responder for all issued certificates","It anchors trust and signs subordinate CA certificates in the chain","It performs daily certificate enrollment requests from end users online"], correct:2, explanation:"The root CA is the trust anchor that signs subordinate CAs; it typically does not issue end-entity certs directly to keep the root protected." },
  { id:50313, domain:3, level:3, question:"Why is an offline root CA considered a security architecture best practice?", options:["It allows the root to issue end-entity certificates much more quickly","It eliminates the need for any certificate revocation mechanism entirely","It permits the root private key to be shared widely among administrators","It keeps the most critical signing key disconnected, reducing compromise risk"], correct:3, explanation:"Keeping the root offline minimizes exposure of the highest-value key. Subordinate CAs handle issuance; revocation is still required regardless." },
  { id:50314, domain:3, level:1, question:"What is the purpose of cross-certification between two separate PKI hierarchies?", options:["It merges both hierarchies into a single root with one combined key","It revokes all certificates issued by the opposing certificate authority","It establishes mutual trust so each domain can validate the other's certs","It forces both organizations to share one common offline root key in such deployments"], correct:2, explanation:"Cross-certification lets two PKIs trust each other's certificates without merging hierarchies or sharing a single root key." },
  { id:50315, domain:3, level:2, question:"A bridge CA is introduced primarily to solve which scalability problem?", options:["The combinatorial explosion of pairwise cross-certifications among many PKIs","The need to issue more certificates per second than one CA allows as a general rule","The requirement to store all private keys inside a single HSM device in such deployments","The inability of OCSP to respond to high volumes of validation requests"], correct:0, explanation:"A bridge CA provides a hub so each PKI cross-certifies once with the bridge instead of with every other PKI pairwise." },
  { id:50316, domain:3, level:2, question:"Which mechanism allows a relying party to check certificate revocation status in real time per certificate?", options:["Certificate Revocation List downloaded and cached on a periodic basis","Embedding the full certificate chain into every signed email message","Manually phoning the certificate authority to confirm the cert validity","Online Certificate Status Protocol querying the responder for one cert"], correct:3, explanation:"OCSP queries status for an individual certificate in near real time. CRLs are periodically downloaded lists, less timely than per-cert OCSP." },
  { id:50317, domain:3, level:2, question:"What problem does OCSP stapling address compared to standard OCSP?", options:["It lets the server present a recent signed status, improving privacy and load","It removes the need for certificates to ever be revoked at all across environments","It allows clients to issue their own certificates without a CA involved","It replaces TLS entirely with a lighter-weight revocation-only protocol"], correct:0, explanation:"With stapling the server fetches and presents a signed OCSP response, reducing OCSP responder load and not exposing client browsing to the responder." },
  { id:50318, domain:3, level:2, question:"Which is the correct general ordering of the key management lifecycle?", options:["Destruction, rotation, storage, distribution, then finally generation","Generation, distribution, storage, rotation, then eventual destruction","Storage, generation, destruction, distribution, then key rotation last","Distribution, destruction, generation, storage, then rotation lastly"], correct:1, explanation:"Keys are generated, distributed, stored, rotated as needed, and eventually destroyed. The other orderings violate logical lifecycle sequencing." },
  { id:50319, domain:3, level:2, question:"What is the main architectural reason to enforce regular key rotation?", options:["It guarantees encrypted data can never be decrypted by anyone again","It removes the requirement to ever securely store any cryptographic key","It limits the amount of data exposed if a single key is compromised","It allows the same key to be reused safely across unlimited datasets"], correct:2, explanation:"Rotation bounds the data protected by any one key, limiting exposure on compromise. Keys still must be stored securely throughout their life." },
  { id:50320, domain:3, level:3, question:"Key escrow introduces which primary architectural tradeoff?", options:["It improves performance at the cost of weaker encryption algorithms","It eliminates the need for any key rotation or destruction procedures","It enables recovery access but creates a high-value compromise target","It guarantees perfect forward secrecy for all escrowed session keys"], correct:2, explanation:"Escrow allows authorized recovery but concentrates risk in the escrow store. It does not provide forward secrecy nor remove rotation needs." },
  { id:50321, domain:3, level:1, question:"What is the primary function of a Hardware Security Module (HSM)?", options:["To accelerate web page rendering for cryptographic-heavy applications","To generate, store, and use keys within tamper-resistant hardware","To replace the need for any certificate authority in a PKI design","To serve as the primary database for all application user records"], correct:1, explanation:"HSMs provide tamper-resistant generation, storage, and use of keys so private keys never leave the device in plaintext." },
  { id:50322, domain:3, level:2, question:"FIPS 140-2 Level 3 adds which key protection capability over Level 2?", options:["Identity-based authentication and tamper response that zeroizes keys","Only basic role-based authentication without any physical protections","Mandatory cloud connectivity for all cryptographic module operations","Removal of all physical security in favor of software attestation only"], correct:0, explanation:"Level 3 adds identity-based authentication and physical tamper-response/zeroization. Level 2 only requires tamper-evidence and role-based authentication." },
  { id:50323, domain:3, level:2, question:"What is key wrapping in an envelope encryption architecture?", options:["Hashing the data key so it can never be recovered or used again across environments","Distributing the same data key to all clients without any protection","Storing the data key in plaintext alongside the encrypted data it protects","Encrypting a data key with a separate key-encryption key for protection"], correct:3, explanation:"Key wrapping encrypts a data-encryption key with a key-encryption key, central to envelope encryption. Plaintext storage or hashing the key defeats the purpose." },
  { id:50324, domain:3, level:2, question:"Envelope encryption is commonly used in cloud KMS designs because it enables what?", options:["Storing every data record's full key inside the KMS without any limits for this purpose","Encrypting unlimited data while only protecting and rotating a small master key","Avoiding encryption of the actual data and only encrypting metadata fields","Replacing all symmetric encryption with slower asymmetric operations in such deployments"], correct:1, explanation:"Envelope encryption wraps per-data keys under a master key, so the KMS manages just the master key while data keys scale with the data." },
  { id:50325, domain:3, level:2, question:"What distinguishes BYOK (Bring Your Own Key) from HYOK (Hold Your Own Key)?", options:["BYOK keeps keys entirely on premises while HYOK uploads them to the cloud","Both terms mean exactly the same thing with no architectural difference at all","HYOK requires no HSM whereas BYOK always mandates a dedicated HSM in such deployments","BYOK imports customer keys into the cloud KMS while HYOK keeps them external"], correct:3, explanation:"BYOK imports customer-generated keys into the provider's KMS; HYOK keeps keys under exclusive customer control, often external to the provider." },
  { id:50326, domain:3, level:2, question:"During a TLS 1.3 handshake, what is primarily negotiated and established?", options:["A persistent symmetric password reused across all future sessions","Shared session keys and the agreed cipher suite for the connection","The client's permanent private key transmitted to the server under typical conditions","A certificate revocation list downloaded for the entire domain for this purpose"], correct:1, explanation:"The handshake establishes ephemeral shared session keys and negotiates parameters. Private keys are never transmitted during the handshake." },
  { id:50327, domain:3, level:2, question:"Perfect forward secrecy in TLS is achieved primarily through what mechanism?", options:["Reusing a single long-term RSA key for every session's key exchange","Storing all session keys in escrow for later authorized recovery across environments","Ephemeral Diffie-Hellman key exchange generating unique per-session keys","Disabling certificate validation to speed up the handshake process"], correct:2, explanation:"Ephemeral DH (DHE/ECDHE) creates unique session keys so compromising the long-term key does not expose past sessions. Static RSA key exchange lacks PFS." },
  { id:50328, domain:3, level:1, question:"What does mutual TLS (mTLS) add beyond standard server-authenticated TLS?", options:["It encrypts data twice using two different symmetric algorithms in series","It removes the need for the server to present any certificate at all","It requires the client to also present a certificate authenticating itself","It downgrades the connection to a weaker cipher for compatibility reasons"], correct:2, explanation:"mTLS requires both endpoints to present certificates, authenticating the client as well as the server. It does not weaken or double-encrypt the channel." },
  { id:50329, domain:3, level:2, question:"Certificate pinning in a mobile application primarily mitigates which threat?", options:["Slow performance during the initial TLS handshake on cellular networks","The inability of the device to store any certificates locally on disk","Excessive battery drain caused by repeated cryptographic operations","A fraudulent or mis-issued certificate from a compromised or rogue CA"], correct:3, explanation:"Pinning binds the app to a known cert or key, blocking rogue/mis-issued CA certificates from being accepted. It is not a performance feature." },
  { id:50330, domain:3, level:3, question:"An architect plans for cryptographic agility. Which design choice best supports it?", options:["Abstracting crypto behind interfaces so algorithms can be swapped centrally","Hard-coding a single approved algorithm directly throughout the codebase","Storing algorithm identifiers nowhere so migrations require full rewrites","Embedding key material and algorithm choices into compiled binaries only"], correct:0, explanation:"Crypto-agility means abstracting algorithm selection so it can change without rewriting applications. Hard-coding algorithms prevents agile migration." },
  { id:50331, domain:3, level:2, question:"Why should an enterprise begin post-quantum cryptography planning before quantum computers are practical?", options:["Quantum computers already routinely break all symmetric encryption today","Harvest-now-decrypt-later attacks capture data now for future decryption","Post-quantum algorithms are already mandatory for every legacy protocol","Classical algorithms have all been formally deprecated and removed already"], correct:1, explanation:"Adversaries can record encrypted data now to decrypt once quantum capability exists, so long-lived secrets need PQC migration planning early." },
  { id:50332, domain:3, level:2, question:"Which class of algorithm is most threatened by large-scale quantum computers via Shor's algorithm?", options:["Asymmetric algorithms based on integer factorization and discrete logs","Symmetric ciphers such as AES used with sufficiently long key lengths","Cryptographic hash functions like SHA-256 used for integrity checking","Message authentication codes built on keyed symmetric primitives in this scenario"], correct:0, explanation:"Shor's algorithm breaks factoring and discrete-log problems (RSA, ECC). Symmetric and hash algorithms are weakened by Grover's but not broken outright." },
  { id:50333, domain:3, level:3, question:"How does Grover's algorithm affect symmetric key strength, and what is the architectural response?", options:["It fully breaks AES regardless of key length, requiring abandonment of AES","It has no measurable effect on symmetric ciphers under any circumstances","It halves effective key strength, so doubling the key length restores margin","It only impacts hash functions and leaves symmetric encryption untouched"], correct:2, explanation:"Grover's gives a quadratic speedup, roughly halving effective symmetric strength; using AES-256 instead of AES-128 preserves a safe margin." },
  { id:50334, domain:3, level:1, question:"What does homomorphic encryption enable that traditional encryption does not?", options:["Encrypting data far faster than any symmetric block cipher available","Eliminating the need for any key management throughout the system in practice","Guaranteeing non-repudiation of every encrypted message automatically","Performing computations directly on ciphertext without decrypting it first"], correct:3, explanation:"Homomorphic encryption permits computation on encrypted data, yielding encrypted results. It is not faster than symmetric encryption nor a key-management replacement." },
  { id:50335, domain:3, level:3, question:"Format-preserving encryption (FPE) is most appropriate in which architectural situation?", options:["Encrypting multi-gigabyte video files for long-term archival storage","Encrypting a credit card number while keeping the same length and format","Hashing passwords irreversibly before storing them in a credentials table","Establishing a shared session key during a TLS handshake negotiation"], correct:1, explanation:"FPE preserves the data's original format and length, ideal for fitting ciphertext into legacy fields like card numbers. It is not a hashing or key-exchange tool." },
  { id:50336, domain:3, level:2, question:"What is the fundamental architectural difference between tokenization and encryption?", options:["Tokenization is simply encryption using a slightly different block size value as a general rule","Encryption stores a lookup table while tokenization uses a mathematical cipher in such deployments","Tokenization substitutes data with a token mapped in a vault, no algorithmic reversibility","Both are identical and the terms are used interchangeably in all standards by design in this scenario"], correct:2, explanation:"Tokenization replaces sensitive data with a surrogate token referencing a secure vault; encryption mathematically transforms data using a key." },
  { id:50337, domain:3, level:2, question:"What is the primary purpose of a secrets management system in modern architectures?", options:["To compile application source code with cryptographic optimizations enabled","To centrally store, control, and audit access to credentials and keys","To replace the need for transport-layer encryption between services","To generate random user passwords that are never stored anywhere in practice"], correct:1, explanation:"Secrets managers centralize storage, access control, rotation, and auditing of credentials, keys, and tokens, avoiding hard-coded secrets." },
  { id:50338, domain:3, level:2, question:"Why is sufficient entropy critical when generating cryptographic keys?", options:["High entropy slows down all encryption operations to unusable speeds","Entropy only matters for hashing and is irrelevant to key generation","Low entropy makes keys predictable and vulnerable to guessing attacks","Keys with low entropy automatically rotate themselves to compensate"], correct:2, explanation:"Insufficient entropy yields predictable keys an attacker can guess or brute-force. Entropy is essential precisely for key and nonce generation." },
  { id:50339, domain:3, level:2, question:"What distinguishes a true random number generator (TRNG) from a pseudo-random one (PRNG)?", options:["A PRNG uses physical noise while a TRNG runs a deterministic algorithm","Both produce identical output given the same seed value every time in this scenario","A TRNG derives randomness from physical processes rather than an algorithm","A TRNG can only generate numbers far slower than is ever usable in most designs"], correct:2, explanation:"TRNGs harvest entropy from physical phenomena; PRNGs deterministically expand a seed. A seeded PRNG repeats output, which a TRNG does not." },
  { id:50340, domain:3, level:2, question:"Shamir's Secret Sharing splits a key such that what condition is required to reconstruct it?", options:["A threshold m of the total n shares must be combined to recover it","All shares without exception must be combined to recover the secret key","Any single share alone is sufficient to fully reconstruct the secret","Shares can never be combined and the secret is permanently destroyed"], correct:0, explanation:"Shamir's scheme is an m-of-n threshold: any m shares reconstruct the secret, while fewer than m reveal nothing. It does not require all shares." },
  { id:50341, domain:3, level:1, question:"What does dual control mean in the context of cryptographic key management?", options:["A single trusted administrator performs all sensitive key operations alone","Keys are duplicated and stored in two separate geographic locations in most designs","Every key operation is automatically performed twice for redundancy","Two or more authorized people must act together to perform a key operation"], correct:3, explanation:"Dual control requires two or more people to jointly perform a sensitive operation, preventing unilateral action. It is not about duplicating keys." },
  { id:50342, domain:3, level:2, question:"Split knowledge as a key management control means what specifically?", options:["One person knows the key while another merely observes the operation","The key is split across files but any one file fully reveals the key","Knowledge of the key is shared publicly to ensure transparency and audit","No single person knows the complete key; each holds only a component"], correct:3, explanation:"Split knowledge ensures no individual possesses the full key; each custodian holds only a part, so collusion is required to reconstruct it." },
  { id:50343, domain:3, level:1, question:"What does the cryptoperiod of a key define?", options:["The maximum file size that may be encrypted with that particular key","The number of certificate authorities that endorsed the key's creation","The physical temperature range an HSM may operate the key within in this scenario","The time span during which a key is authorized for active use in this context"], correct:3, explanation:"A cryptoperiod is the timeframe a key may be used before retirement or rotation. It is a time bound, not a data-size or environmental limit." },
  { id:50344, domain:3, level:2, question:"Which X.509 certificate field binds the certificate to the entity it identifies?", options:["The Signature Algorithm field listing the hashing method employed","The Validity field specifying the not-before and not-after dates in this scenario","The Serial Number field uniquely identifying the certificate issuance","The Subject field containing the entity's distinguished name details"], correct:3, explanation:"The Subject field identifies the entity the certificate represents. Validity, serial number, and signature algorithm describe the cert but not the identity binding." },
  { id:50345, domain:3, level:1, question:"What is the purpose of the Key Usage extension in an X.509 certificate?", options:["It constrains the cryptographic operations the key is permitted to perform","It records the certificate's price and licensing terms from the issuing CA","It lists the physical addresses of all servers presenting the certificate","It stores the encrypted private key for backup and recovery purposes"], correct:0, explanation:"Key Usage limits operations such as digital signature, key encipherment, or cert signing. Private keys are never stored inside the certificate." },
  { id:50346, domain:3, level:2, question:"Code signing primarily provides which assurances to the consumer of software?", options:["Authenticity of the publisher and integrity that code is unmodified","Confidentiality of the source code so it cannot be reverse engineered","Guaranteed absence of any vulnerabilities or malware in the software","Automatic encryption of all data the signed application processes"], correct:0, explanation:"Code signing verifies the publisher's identity and that the code is unaltered since signing. It does not guarantee the code is bug- or malware-free." },
  { id:50347, domain:3, level:3, question:"How does S/MIME secure email messages architecturally?", options:["It relies on a decentralized web of trust with no certificate authorities","It uses X.509 certificates and PKI for signing and encrypting messages","It encrypts only the subject line while leaving the body in plaintext","It tunnels all email through an IPsec VPN before any SMTP delivery"], correct:1, explanation:"S/MIME uses X.509 certificates from a PKI for message signing and encryption. PGP, by contrast, traditionally uses a decentralized web of trust." },
  { id:50348, domain:3, level:2, question:"What is a defining architectural characteristic of PGP/OpenPGP trust compared to S/MIME?", options:["It mandates a centralized hierarchical certificate authority structure","It uses a decentralized web of trust where users vouch for each other","It cannot encrypt message bodies and only supports digital signatures","It requires an offline root CA to issue every individual user key"], correct:1, explanation:"PGP traditionally uses a web of trust with peer endorsements, unlike S/MIME's centralized PKI hierarchy of certificate authorities." },
  { id:50349, domain:3, level:2, question:"In IPsec, what is the role of the Internet Key Exchange (IKE) protocol?", options:["It encrypts the actual payload data carried inside each IP packet by design","It replaces the need for any encryption by authenticating endpoints only","It negotiates security associations and derives keys for the IPsec tunnel","It performs certificate revocation checks for all VPN participants in most designs"], correct:2, explanation:"IKE negotiates security associations and establishes keying material; ESP/AH then protect the actual traffic using those keys." },
  { id:50350, domain:3, level:2, question:"What distinguishes IPsec ESP from IPsec AH?", options:["ESP provides confidentiality and integrity while AH provides integrity only","AH provides encryption while ESP provides only authentication of headers","Both ESP and AH provide identical confidentiality and authentication services","ESP works only in transport mode while AH works only in tunnel mode"], correct:0, explanation:"ESP offers confidentiality plus integrity/authentication; AH offers integrity/authentication without encryption. Both support transport and tunnel modes." },
  { id:50351, domain:3, level:2, question:"Which encryption approach protects an entire storage volume transparently below the file system?", options:["Field-level encryption applied selectively to individual database columns","Full-disk encryption operating at the block device or volume layer","Application-layer encryption performed inside each business application","Transport encryption applied only while data moves across the network"], correct:1, explanation:"Full-disk encryption operates at the volume/block layer, transparently protecting all data at rest. Field-level and application-layer encryption are more granular." },
  { id:50352, domain:3, level:2, question:"What is a key architectural advantage of field-level (column) encryption in a database?", options:["It encrypts the entire database file as one indivisible large blob in most designs","It removes the need to manage any encryption keys whatsoever under typical conditions","It guarantees the database can never be backed up or replicated for this purpose","It protects specific sensitive fields while leaving others queryable normally"], correct:3, explanation:"Field-level encryption protects only chosen sensitive columns, preserving the ability to query non-sensitive fields. It still requires key management." },
  { id:50353, domain:3, level:3, question:"An architect must decide between transparent database encryption (TDE) and application-layer encryption for highly sensitive fields. Which factor most favors application-layer encryption?", options:["A need to maximize raw query performance above all other concerns","A requirement that the database administrator never see plaintext values","A desire to avoid any key management responsibilities in the application","A goal to encrypt the whole database with the least development effort"], correct:1, explanation:"Application-layer encryption keeps plaintext from the DBA and DB engine; TDE decrypts transparently so the DB and its admins can access plaintext." },
  { id:50354, domain:3, level:2, question:"Which NIST publication is the primary reference for key management recommendations?", options:["NIST Special Publication 800-53 on security and privacy controls by design","NIST Special Publication 800-30 on conducting risk assessments in this scenario","NIST Special Publication 800-61 on incident handling guidance in this context","NIST Special Publication 800-57 on cryptographic key management in most designs"], correct:3, explanation:"SP 800-57 covers key management guidance. SP 800-53 is controls, 800-30 is risk assessment, and 800-61 is incident handling." },
  { id:50355, domain:3, level:2, question:"During a TLS connection, an attacker forces the use of an obsolete weak cipher suite. What attack is this and what mitigation applies?", options:["A padding oracle attack mitigated by switching to authenticated encryption in practice","A downgrade attack mitigated by disabling legacy protocols and enforcing minimums","A birthday attack mitigated by using a hash with a longer output digest in such deployments","A side-channel attack mitigated by adding constant-time implementations across environments"], correct:1, explanation:"Forcing weaker negotiated parameters is a downgrade attack; disabling legacy protocols/ciphers and enforcing minimum versions mitigates it." },
  { id:50356, domain:3, level:3, question:"A padding oracle attack against CBC-mode encryption is best mitigated architecturally by what?", options:["Using authenticated encryption such as AES-GCM instead of unauthenticated CBC","Increasing the symmetric key length from 128 bits up to 256 bits in such deployments","Switching from a block cipher to an insecure stream cipher design across environments","Reusing the same initialization vector across all encrypted messages by design"], correct:0, explanation:"Padding oracles exploit unauthenticated CBC error responses; authenticated encryption (AEAD) like GCM eliminates the oracle. Key length does not address it." },
  { id:50357, domain:3, level:2, question:"The birthday attack is most relevant to which cryptographic concern?", options:["Recovering a symmetric key by exhaustively trying every possible value","Decrypting RSA ciphertext by factoring the public modulus quickly","Finding collisions in a hash function faster than brute force suggests","Intercepting a Diffie-Hellman exchange to learn the shared session key"], correct:2, explanation:"The birthday paradox means hash collisions are found in roughly 2^(n/2) work, driving minimum hash output sizes. It is not a key-recovery or factoring attack." },
  { id:50358, domain:3, level:3, question:"Which architectural mitigation best addresses timing side-channel attacks on cryptographic operations?", options:["Increasing the cryptoperiod so keys are rotated far less frequently","Logging every cryptographic operation's exact duration for later review","Switching all algorithms to ECB mode for faster predictable timing","Using constant-time implementations that avoid data-dependent branching"], correct:3, explanation:"Constant-time code removes data-dependent timing variations attackers measure. Logging timings or using ECB does not mitigate the leak." },
  { id:50359, domain:3, level:2, question:"Why must an initialization vector (IV) for CBC mode be unpredictable?", options:["A predictable IV enables chosen-plaintext attacks against the first block","The IV must be secret or the entire ciphertext is trivially decrypted","An unpredictable IV doubles the effective symmetric key length used","IV predictability only affects performance and never affects security"], correct:0, explanation:"A predictable CBC IV permits chosen-plaintext attacks; the IV need not be secret but must be unpredictable. It does not change key length." },
  { id:50360, domain:3, level:1, question:"What is the consequence of reusing a nonce with the same key in AES-GCM?", options:["It strengthens the authentication tag by adding extra entropy each time","It has no security impact as long as the plaintext differs each time","It can catastrophically break confidentiality and allow tag forgery","It only slows performance but preserves all security guarantees across environments"], correct:2, explanation:"Nonce reuse in GCM can leak the authentication key and reveal plaintext XOR relationships, breaking both confidentiality and integrity guarantees." },
  { id:50361, domain:3, level:3, question:"Which approach best supports secure key distribution to many endpoints at scale?", options:["Emailing the shared symmetric key in plaintext to each endpoint owner","Hard-coding the same key into every device firmware image at the factory","Posting the key on an internal wiki page restricted to administrators","Using a centralized KMS with authenticated, encrypted key delivery channels"], correct:3, explanation:"A KMS with authenticated, encrypted delivery scales secure distribution. Emailing, hard-coding, or wiki-posting keys all expose them dangerously." },
  { id:50362, domain:3, level:1, question:"What is the main purpose of salting before hashing stored passwords?", options:["To encrypt the password so it can later be decrypted when needed in such deployments","To shorten the resulting hash for more efficient database storage","To prevent identical passwords from producing identical hash values","To allow the password to be recovered if the user forgets it in practice"], correct:2, explanation:"A unique salt per password ensures identical passwords hash differently, defeating precomputed rainbow tables. Hashing is not reversible decryption." },
  { id:50363, domain:3, level:2, question:"Why are purpose-built password hashing functions like bcrypt, scrypt, or Argon2 preferred over a single SHA-256 pass?", options:["They are far faster, allowing more login attempts per second to be processed","They produce reversible output so passwords can be recovered on demand","They eliminate the need for any salt because collisions cannot occur","They are deliberately slow and memory-hard, resisting brute-force cracking"], correct:3, explanation:"Adaptive functions are intentionally slow and memory-hard to resist offline cracking; a single fast SHA-256 is too quick to brute-force. They still use salts." },
  { id:50364, domain:3, level:3, question:"An architect designs key storage for a multi-tenant SaaS. Which approach best isolates tenant keys?", options:["Sharing one master key across all tenants for operational simplicity for this purpose","Using per-tenant keys wrapped under tenant-specific or isolated key material","Storing all tenant keys in plaintext within the application database as a general rule","Deriving every tenant key from the same fixed public constant value in such deployments"], correct:1, explanation:"Per-tenant key isolation limits blast radius if one tenant's key is exposed. A shared master or fixed-derived key breaks isolation between tenants." },
  { id:50365, domain:3, level:2, question:"What is the architectural role of a key encryption key (KEK) versus a data encryption key (DEK)?", options:["The DEK encrypts data while the KEK encrypts and protects the DEK","The KEK encrypts data directly while the DEK protects only the KEK","Both KEK and DEK encrypt the same data simultaneously for redundancy","The KEK and DEK are identical and the distinction is purely cosmetic"], correct:0, explanation:"DEKs encrypt the actual data; KEKs wrap/protect the DEKs, a core pattern in envelope encryption enabling scalable key management." },
  { id:50366, domain:3, level:2, question:"Why is RSA generally not used to encrypt large messages directly?", options:["Asymmetric operations are slow and limited to data smaller than the key","RSA cannot encrypt any data and is only ever used for hashing operations","RSA encryption output is always smaller than its plaintext input data","RSA requires the same key for encryption and decryption like AES does"], correct:0, explanation:"RSA is slow and can only encrypt data smaller than the modulus, so it is used to wrap symmetric keys rather than bulk data." },
  { id:50367, domain:3, level:2, question:"Elliptic curve cryptography (ECC) offers what advantage over RSA at equivalent security?", options:["It eliminates the need for any random number generation entirely in such deployments","It is a symmetric algorithm requiring only one shared secret key across environments","It uses substantially smaller keys for the same security strength level","It is immune to quantum attacks unlike all RSA-based schemes in this scenario"], correct:2, explanation:"ECC achieves comparable strength with much smaller keys, saving bandwidth and computation. It is still asymmetric and vulnerable to quantum Shor's algorithm." },
  { id:50368, domain:3, level:1, question:"What does the Diffie-Hellman protocol primarily accomplish?", options:["It allows two parties to derive a shared secret over an insecure channel","It signs messages to provide non-repudiation between two parties by design","It encrypts bulk data faster than any available symmetric cipher in this scenario","It revokes compromised certificates across a distributed PKI hierarchy"], correct:0, explanation:"Diffie-Hellman lets two parties agree on a shared secret over a public channel. It does not by itself sign messages or encrypt bulk data." },
  { id:50369, domain:3, level:2, question:"A classic Diffie-Hellman exchange without authentication is vulnerable to which attack, and what mitigates it?", options:["A man-in-the-middle attack mitigated by authenticating the exchange via signatures or certificates","A brute-force key search mitigated by simply shortening the modulus size in this scenario in this context","A replay attack mitigated by reusing the same ephemeral keys repeatedly in this context in most designs","A padding oracle attack mitigated by adding PKCS padding to the exchange in most designs under typical conditions"], correct:0, explanation:"Unauthenticated DH allows a MITM to relay and substitute values; authenticating the exchange with signatures/certificates prevents impersonation." },
  { id:50370, domain:3, level:1, question:"What is the primary purpose of a Certificate Signing Request (CSR)?", options:["To revoke an existing certificate that has been compromised already","To submit the public key and identity details to a CA for signing","To transmit the private key securely to the certificate authority","To distribute the issued certificate to all relying parties at once"], correct:1, explanation:"A CSR conveys the public key and subject details for the CA to sign; the private key never leaves the requester and is not in the CSR." },
  { id:50371, domain:3, level:2, question:"Why should the private key never be included in a Certificate Signing Request?", options:["Including it would make the CSR file too large to transmit efficiently","Exposing the private key would compromise the entire key pair's security","The CA already possesses a copy of every requester's private key across environments","CSRs are encrypted so including the private key would be redundant"], correct:1, explanation:"The private key must remain solely with its owner; exposing it in a CSR would defeat the security of the asymmetric key pair." },
  { id:50372, domain:3, level:2, question:"What is the architectural function of an intermediate (issuing) CA in a PKI?", options:["It serves as the ultimate trust anchor distributed to all relying parties","It issues end-entity certificates so the root CA can remain offline","It maintains the master list of all private keys in the organization","It performs all encryption and decryption for end-entity applications"], correct:1, explanation:"Intermediate CAs issue end-entity certs, letting the root stay offline and protected. The root, not the intermediate, is the trust anchor." },
  { id:50373, domain:3, level:3, question:"If an intermediate CA's private key is compromised, what is the most appropriate architectural response?", options:["Revoke only the specific end-entity certificates known to be misused","Rotate the root CA key while leaving the intermediate in service for this purpose","Revoke the intermediate CA certificate, invalidating all certs it issued","Ignore it because intermediate compromise does not affect issued certs"], correct:2, explanation:"Revoking the intermediate invalidates everything beneath it, since all its issued certs derive trust from it. Revoking only known-misused certs is insufficient." },
  { id:50374, domain:3, level:1, question:"What does certificate chain validation verify for a presented end-entity certificate?", options:["That the certificate's private key matches a stored copy at the client","That the server has the fastest available cipher suite enabled in practice","That the certificate links via signatures up to a trusted root anchor","That the certificate was issued within the last twenty-four hours only"], correct:2, explanation:"Chain validation confirms each cert is signed by the next up to a trusted root and that none are expired or revoked. It does not store private keys." },
  { id:50375, domain:3, level:2, question:"Which factor most strongly drives the appropriate length of a cryptoperiod for a key?", options:["The aesthetic preference of the security architecture review board","The brand of HSM vendor selected for the deployment environment in this context","The number of employees who have heard of the encryption algorithm","The sensitivity of data and the volume encrypted under that key"], correct:3, explanation:"Cryptoperiods are driven by data sensitivity, exposure, and volume of data protected. Vendor brand and headcount are irrelevant to the cryptoperiod." },
  { id:50376, domain:3, level:1, question:"What is the primary security benefit of generating keys inside an HSM rather than externally?", options:["Keys can be generated much faster than any software library allows as a general rule","The private key never exists in plaintext outside the tamper-resistant boundary","It removes the requirement to ever back up or recover the key material across environments","It allows the same key to be exported freely to any external system by design"], correct:1, explanation:"In-HSM generation means the private key never leaves the protected boundary in plaintext, reducing exposure. HSMs restrict, not enable, free export." },
  { id:50377, domain:3, level:2, question:"An organization wants cloud encryption but must retain exclusive control of keys outside the provider. Which model fits?", options:["Provider-managed keys where the cloud generates and holds all keys in such deployments","Default server-side encryption with provider-owned master keys only across environments","Storing the keys in the same bucket as the encrypted cloud data by design in this scenario","Hold Your Own Key where keys remain under exclusive customer control externally"], correct:3, explanation:"HYOK keeps keys external and under exclusive customer control. Provider-managed or default server-side encryption cedes control to the provider." },
  { id:50378, domain:3, level:3, question:"What architectural risk does HSM-as-a-service from a cloud provider introduce compared to on-premises HSMs?", options:["It introduces dependence on the provider and shared-tenancy trust considerations","It makes key generation impossible without local physical hardware present","It guarantees the provider can never access tenant keys under any condition","It removes the need to evaluate FIPS validation of the module entirely in this context"], correct:0, explanation:"Cloud HSM services add provider dependency and trust/tenancy considerations. FIPS validation and provider access models still must be evaluated." },
  { id:50379, domain:3, level:3, question:"Which statement about TLS cipher suite selection is most accurate for a secure architecture?", options:["Enable every cipher suite to maximize client compatibility regardless of strength","Prefer static RSA key exchange to ensure perfect forward secrecy always","Always select the shortest key lengths to optimize handshake performance","Prioritize AEAD suites with forward secrecy and disable known-weak ciphers"], correct:3, explanation:"Secure designs prefer AEAD suites with ephemeral (forward-secret) key exchange and remove weak ciphers. Static RSA lacks forward secrecy." },
  { id:50380, domain:3, level:3, question:"An architect must support legacy clients yet maintain strong security. What is the best approach to cipher configuration?", options:["Disable TLS entirely and fall back to unencrypted communication for legacy clients in this scenario","Enable all historical SSL and TLS versions without restriction for compatibility in this context","Offer a prioritized list favoring strong suites while isolating or sunsetting legacy support","Force every client onto a single weak cipher to simplify the configuration under typical conditions"], correct:2, explanation:"A prioritized strong-first list with a managed sunset for legacy clients balances security and compatibility. Enabling all old protocols is unsafe." },
  { id:50381, domain:3, level:1, question:"What is the main purpose of a message authentication code (MAC)?", options:["To verify integrity and authenticity using a shared secret key as a general rule","To provide confidentiality by encrypting the message before transmission","To establish a shared session key between two communicating endpoints","To provide non-repudiation that holds up in a legal dispute by design"], correct:0, explanation:"A MAC verifies integrity and authenticity with a shared key. Because both parties share the key, it does not provide non-repudiation like a signature." },
  { id:50382, domain:3, level:2, question:"In authenticated encryption with associated data (AEAD), what is the associated data?", options:["Additional data that is authenticated but not encrypted, such as headers","The symmetric key material transmitted alongside the ciphertext securely","A second ciphertext encrypted with a completely different key value","The certificate chain appended to validate the sender's identity in practice"], correct:0, explanation:"Associated data (like routing headers) is authenticated for integrity but left unencrypted, while the payload is both encrypted and authenticated." },
  { id:50383, domain:3, level:3, question:"Why is hard-coding cryptographic keys into application source code a poor architectural practice?", options:["Keys cannot be rotated and are exposed to anyone who reads the code or binary","Compiled binaries run more slowly when keys are embedded inside them for this purpose","Source-code keys are automatically encrypted and therefore always safe in practice","It violates licensing terms of most commercial cryptography libraries as a general rule"], correct:0, explanation:"Embedded keys cannot be rotated and are extractable from source or binaries, a serious exposure. Secrets belong in a managed vault." },
  { id:50384, domain:3, level:1, question:"What is the primary advantage of using ephemeral keys for each session?", options:["It removes the need for any long-term authentication credentials by design","Compromise of one session key does not expose other sessions' data","It allows the same key to be cached and reused indefinitely later","It increases the cryptoperiod so rotation is never required again"], correct:1, explanation:"Ephemeral per-session keys provide forward secrecy: compromising one does not endanger others. They are short-lived, not cached for reuse." },
  { id:50385, domain:3, level:1, question:"What is non-repudiation in the context of cryptographic services?", options:["The guarantee that a message remains confidential during transmission","The assurance that a key will never need rotation during its life","The inability of a sender to deny having signed or sent a message","The capability to recover encrypted data when a key is lost under typical conditions"], correct:2, explanation:"Non-repudiation prevents a signer from denying their action, achieved via digital signatures with a private key. It is distinct from confidentiality." },
  { id:50386, domain:3, level:3, question:"Which scenario most clearly requires asymmetric rather than symmetric cryptography?", options:["Establishing trust and exchanging keys between parties with no prior shared secret","Encrypting a large archive on a single host with no key exchange needed in such deployments","Performing fast bulk encryption of streaming video on one device across environments","Hashing log files for tamper-evident integrity verification locally by design in this scenario"], correct:0, explanation:"Asymmetric crypto shines where parties lack a pre-shared secret and need key exchange or signatures. Local bulk encryption favors symmetric ciphers." },
  { id:50387, domain:3, level:3, question:"An architect is selecting between AES-CBC with HMAC and AES-GCM for a new protocol. Which consideration most favors AES-GCM?", options:["A requirement to support extremely old hardware lacking any AES support in such deployments","A desire for single-pass authenticated encryption with lower error-prone composition","A need to encrypt without authenticating the ciphertext at all by design in this scenario","A goal to maximize the number of separate keys used per message in this scenario in this context"], correct:1, explanation:"GCM provides single-pass AEAD, avoiding error-prone encrypt-then-MAC composition mistakes common with CBC+HMAC. It needs hardware/software support for GCM." },
  { id:50388, domain:3, level:1, question:"What does perfect forward secrecy specifically protect against?", options:["An attacker brute-forcing a weak symmetric cipher in real time across environments","The accidental reuse of an initialization vector across messages by design","Future compromise of a long-term key exposing previously recorded sessions","A certificate authority being compromised and issuing rogue certs in this context"], correct:2, explanation:"PFS ensures past session keys cannot be derived even if the long-term private key is later compromised. It does not address CA compromise directly." },
  { id:50389, domain:3, level:2, question:"Which control most directly prevents a single rogue administrator from exfiltrating a master key?", options:["Increasing the master key length from 128 bits to 256 bits for this purpose","Enforcing split knowledge and dual control over key operations in practice","Rotating the master key on a more frequent monthly schedule as a general rule","Logging all key access events to a centralized audit system in such deployments"], correct:1, explanation:"Split knowledge and dual control require collusion of multiple custodians, preventing unilateral exfiltration. Longer keys or logging do not stop a lone insider." },
  { id:50390, domain:3, level:1, question:"What is the security purpose of zeroization in a cryptographic module?", options:["Resetting the device counter to zero for performance benchmarking in this scenario","Encrypting the key with a zero-value initialization vector for storage in this context","Overwriting key material so it cannot be recovered after destruction or tamper","Setting the key value to all zeros so it becomes a known weak key under typical conditions"], correct:2, explanation:"Zeroization erases key material on tamper or decommission so it cannot be recovered. It is destruction, not setting keys to a weak all-zero value." },
  { id:50391, domain:3, level:3, question:"An organization must migrate from SHA-1 to SHA-256 across many systems. Which approach best embodies crypto-agility?", options:["Replacing SHA-1 in each system independently with no central coordination","Hard-coding SHA-256 directly to avoid any future configuration complexity","Using configurable algorithm references so the hash can be updated centrally","Continuing SHA-1 indefinitely since migration introduces operational risk"], correct:2, explanation:"Centralized, configurable algorithm references let the hash be updated without rewriting each system, the essence of crypto-agility." },
  { id:50392, domain:3, level:2, question:"Why is SHA-1 deprecated for digital signatures and certificates?", options:["It produces output too long for modern certificate fields to store in most designs","Practical collision attacks undermine its integrity and signature guarantees","It is a symmetric algorithm unsuitable for asymmetric signature schemes","It requires hardware acceleration that is no longer manufactured today"], correct:1, explanation:"Demonstrated collision attacks make SHA-1 unsuitable for signatures where collisions can forge documents. SHA-1 is a hash, not a symmetric cipher." },
  { id:50393, domain:3, level:2, question:"What is the architectural benefit of certificate transparency logs?", options:["They encrypt all issued certificates to keep them confidential from attackers","They replace OCSP and CRLs as the sole revocation mechanism available","They publicly record issued certificates so mis-issuance can be detected","They generate private keys on behalf of domain owners automatically"], correct:2, explanation:"CT logs publicly append issued certificates so domain owners can detect mis-issuance. They do not encrypt certs, generate keys, or replace revocation." },
  { id:50394, domain:3, level:3, question:"Which best describes the trust model risk of a single compromised public CA?", options:["It only affects certificates issued before the compromise occurred","It cannot affect TLS because browsers ignore single CA failures in practice","It can issue trusted certificates for any domain, enabling impersonation","It automatically revokes itself the moment compromise is detected in such deployments"], correct:2, explanation:"A trusted CA can issue certs for any domain, so its compromise enables broad impersonation, motivating CT and pinning. Self-revocation is not automatic." },
  { id:50395, domain:3, level:3, question:"An architect needs to protect data in use during processing in an untrusted cloud. Which technology is most relevant?", options:["Full-disk encryption applied to the cloud instance's boot volume in practice","Transport Layer Security applied only between the client and the server","A certificate revocation list checked before each processing request in such deployments","Confidential computing using a hardware-based trusted execution environment"], correct:3, explanation:"Confidential computing uses TEEs to protect data in use during processing. Disk and transport encryption protect data at rest and in transit, not in use." },
  { id:50396, domain:3, level:1, question:"What is the primary cryptographic concern when designing for IoT devices with limited resources?", options:["Devices have unlimited compute so the strongest algorithms are always trivial","Encryption is unnecessary because IoT data is never considered sensitive","Asymmetric operations are always free of cost on small microcontrollers","Constrained compute and power favor lightweight yet still secure algorithms"], correct:3, explanation:"IoT constraints push toward lightweight cryptography that remains secure, since heavy asymmetric operations can be costly on small devices." },
  { id:50397, domain:3, level:3, question:"Why might an architect choose ECDSA over RSA for signatures in a constrained environment?", options:["ECDSA signatures and keys are larger, providing more redundancy in most designs","ECDSA is a symmetric scheme requiring no key pair management under typical conditions","ECDSA is immune to all side-channel attacks by its mathematical design","ECDSA offers comparable security with smaller keys and signatures"], correct:3, explanation:"ECDSA delivers equivalent security with smaller keys/signatures, ideal for constrained devices. It is asymmetric and not inherently side-channel immune." },
  { id:50398, domain:3, level:1, question:"What is the role of a registration authority (RA) in a PKI?", options:["It verifies the identity of requesters before the CA issues certificates","It signs all issued certificates in place of the certificate authority","It stores the private keys of every certificate it has processed in this scenario","It performs encryption of bulk data for end-entity applications in this context"], correct:0, explanation:"An RA validates requester identities and forwards approved requests to the CA, which performs the signing. The RA does not sign or store private keys." },
  { id:50399, domain:3, level:3, question:"An architect is asked whether to use tokenization or encryption to reduce PCI DSS scope for stored card data. Which reasoning is soundest?", options:["Encryption removes card data from systems entirely so scope shrinks to zero by design","Both leave the original card data in place so scope is unchanged either way in this scenario","Tokenization replaces card data with tokens, so systems holding tokens fall out of scope","Tokenization requires storing card numbers in cleartext to map them back in most designs"], correct:2, explanation:"Tokenization removes actual card data from systems, which then handle only tokens and fall out of scope. Encrypted card data still resides in systems within scope." },
  { id:50400, domain:3, level:2, question:"What is a primary architectural drawback of deterministic encryption for sensitive fields?", options:["It cannot encrypt the data at all because outputs are unpredictable in this scenario","It always requires asymmetric keys that are too slow for any field data in this context","It makes the encrypted field impossible to index or compare ever again in most designs","Identical plaintexts yield identical ciphertexts, leaking equality and patterns"], correct:3, explanation:"Deterministic encryption leaks which plaintexts are equal because they map to identical ciphertext, though it does enable equality matching/indexing." },
  { id:50401, domain:3, level:1, question:"What does a certificate's validity period define?", options:["The number of times the certificate's key may be used to sign data in this context","The maximum file size the certificate's key is permitted to encrypt in most designs","The list of domains the certificate is authorized to represent under typical conditions","The window during which the certificate is considered trustworthy if not revoked"], correct:3, explanation:"The validity period (not-before/not-after) defines when the cert is valid, barring revocation. It does not cap usage counts, file sizes, or list domains." },
  { id:50402, domain:3, level:2, question:"Why should certificate validity periods generally be kept relatively short?", options:["Shorter periods make certificates far cheaper to purchase from any CA","Longer periods are technically impossible to configure in modern PKI","Shorter periods limit exposure window and force regular key refresh","Short periods eliminate the need for any revocation infrastructure"], correct:2, explanation:"Short validity limits the window of misuse if a key is compromised and encourages key hygiene. Revocation infrastructure is still needed." },
  { id:50403, domain:3, level:1, question:"What is the function of the Authority Information Access (AIA) extension in a certificate?", options:["It points to the issuer's certificate and OCSP responder locations","It lists the encryption algorithms the certificate is permitted to use","It contains the encrypted backup of the certificate's private key","It records the physical data center location of the issuing CA in this context"], correct:0, explanation:"AIA provides URLs to fetch the issuer certificate and the OCSP responder, aiding chain building and revocation checking." },
  { id:50404, domain:3, level:1, question:"What is the purpose of the Subject Alternative Name (SAN) extension?", options:["To store the subject's encrypted private key for recovery purposes","To define the certificate's revocation reason and its effective date","To specify the symmetric cipher used to protect the certificate file","To list additional identities such as multiple DNS names for one cert"], correct:3, explanation:"SAN lists additional valid identities (DNS names, IPs) for the certificate, which modern browsers require instead of relying on the common name." },
  { id:50405, domain:3, level:3, question:"An architect must decide where to terminate TLS for a microservices platform requiring end-to-end encryption. Which design best meets that requirement?", options:["Terminate TLS at the edge load balancer and send plaintext to all services","Disable TLS internally because the data center network is fully trusted","Terminate TLS at each service but never re-encrypt internal traffic","Use mutual TLS between services so traffic stays encrypted end to end"], correct:3, explanation:"Service-to-service mTLS keeps traffic encrypted and mutually authenticated end to end, unlike edge termination that exposes plaintext internally." },
  { id:50406, domain:3, level:2, question:"What is a session resumption mechanism's main tradeoff in TLS architecture?", options:["It strengthens forward secrecy while making handshakes slower overall","It improves performance but can weaken forward secrecy if mismanaged","It removes the need for certificates during the resumed connection","It encrypts the certificate so attackers cannot read the subject name"], correct:1, explanation:"Resumption (tickets/IDs) cuts handshake cost but, if keys are long-lived or poorly rotated, can undermine forward secrecy." },
  { id:50407, domain:3, level:2, question:"Why is reusing the same RSA key pair for both encryption and signing discouraged?", options:["It causes the key to expire twice as fast as a single-purpose key in such deployments","Separating usage limits cross-protocol attacks and aligns with key-usage controls","Reuse makes RSA operations mathematically impossible to perform by design in this scenario","Signing keys must always be symmetric while encryption keys are asymmetric in this scenario"], correct:1, explanation:"Distinct keys per purpose reduce cross-protocol attack risk and honor key-usage separation. Signing keys are asymmetric, not symmetric." },
  { id:50408, domain:3, level:1, question:"What does the term cryptographic erasure (crypto-shredding) mean?", options:["Physically destroying every storage drive that ever held encrypted data","Destroying the encryption keys so the encrypted data becomes unrecoverable","Overwriting plaintext data with random patterns dozens of times in place","Compressing the ciphertext until it can no longer be decompressed in this context"], correct:1, explanation:"Crypto-shredding renders data unrecoverable by destroying its keys, avoiding the need to wipe the underlying storage media itself." },
  { id:50409, domain:3, level:3, question:"For cloud data that must be sanitized on demand, why is crypto-shredding architecturally attractive?", options:["Destroying the key instantly renders large encrypted datasets unrecoverable","It allows the same key to be reused after the data is sanitized in this scenario","It physically overwrites every replica including immutable backups instantly","It avoids the need to ever encrypt the data in the first place in most designs"], correct:0, explanation:"In distributed/replicated cloud storage, destroying the key effectively sanitizes all copies at once, far simpler than overwriting every replica." },
  { id:50410, domain:3, level:1, question:"What is the main reason to separate signing and encryption certificates for an email user?", options:["It makes both certificates expire on exactly the same calendar date in this scenario","It removes the requirement to validate either certificate's chain of trust","It permits both certificates to share one identical private key value in most designs","It allows encryption keys to be escrowed for recovery while signing keys are not"], correct:3, explanation:"Encryption keys may need escrow for data recovery, while signing keys must not be escrowed to preserve non-repudiation, motivating separation." },
  { id:50411, domain:3, level:1, question:"What is the role of a nonce in cryptographic protocols?", options:["A secret long-term key shared permanently between two communicating parties","A reversible encoding applied to plaintext before it is encrypted","A hash of the certificate used to identify the issuing authority across environments","A number used once to ensure freshness and prevent replay attacks"], correct:3, explanation:"A nonce is a value used once to guarantee freshness and resist replay. It is not a secret long-term key nor an encoding." },
  { id:50412, domain:3, level:2, question:"How does a replay attack threaten a cryptographic protocol, and what mitigates it?", options:["By guessing the key directly, mitigated by using a longer key length","By resending captured valid messages, mitigated by nonces or timestamps","By factoring the public modulus, mitigated by switching to ECC curves","By colliding two hashes, mitigated by salting the input before hashing"], correct:1, explanation:"Replay reuses captured valid messages; nonces, sequence numbers, or timestamps detect and reject stale messages." },
  { id:50413, domain:3, level:2, question:"Which best describes a known-plaintext attack?", options:["The attacker chooses arbitrary plaintexts and observes their ciphertexts","The attacker only has ciphertext and no other information at all by design","The attacker has matching plaintext-ciphertext pairs to deduce the key","The attacker physically extracts the key from a tamper-proof module"], correct:2, explanation:"In a known-plaintext attack, the adversary has plaintext-ciphertext pairs and tries to recover the key. Choosing plaintexts is a chosen-plaintext attack." },
  { id:50414, domain:3, level:3, question:"An architect evaluates whether to deploy post-quantum algorithms now using hybrid key exchange. What does hybrid PQC mean?", options:["Combining a classical and a post-quantum algorithm so both must be broken","Running two symmetric ciphers in sequence to double the key strength","Using post-quantum algorithms only for hashing and not key exchange","Alternating between RSA and ECC randomly on each new connection in such deployments"], correct:0, explanation:"Hybrid key exchange combines a classical and PQC algorithm so an attacker must break both, hedging against immature PQC and quantum threats." },
  { id:50415, domain:3, level:2, question:"Why is algorithm and key length selection guided by anticipated data lifetime?", options:["Short-lived data always requires the strongest possible algorithms available","Data lifetime has no relationship to cryptographic strength requirements","Longer-lived data must resist future advances in cryptanalysis and computing","Only the network bandwidth, not data lifetime, drives algorithm choice"], correct:2, explanation:"Data that must stay confidential for decades needs stronger, future-proof algorithms because cryptanalysis and compute power improve over time." },
  { id:50416, domain:3, level:2, question:"What is the architectural purpose of a key recovery agent?", options:["To rotate all keys automatically without any administrative involvement","To sign every certificate issued by the enterprise certificate authority","To enable authorized recovery of encrypted data when keys are lost","To generate entropy for the random number generator during boot for this purpose"], correct:2, explanation:"A key recovery agent allows authorized recovery of data when keys are lost or unavailable, balanced against the risk of concentrating recovery power." },
  { id:50417, domain:3, level:2, question:"What distinguishes confidentiality from integrity as cryptographic objectives?", options:["Confidentiality detects tampering while integrity keeps the data hidden","Both objectives are achieved automatically by any hashing function alone","Integrity requires a private key while confidentiality requires only a hash","Confidentiality keeps data secret while integrity detects unauthorized change"], correct:3, explanation:"Confidentiality hides data (encryption); integrity detects modification (hashes/MACs/signatures). A hash alone gives integrity, not confidentiality." },
  { id:50418, domain:3, level:2, question:"A design requires both confidentiality and integrity for stored messages. Which composition is most robust and least error-prone?", options:["MAC-then-encrypt using two unrelated keys chosen independently each time","Encrypt the data and rely on the file system checksum for integrity","Hash the plaintext and store the hash unencrypted beside the ciphertext","Encrypt-then-MAC or a dedicated AEAD mode that binds both together"], correct:3, explanation:"Encrypt-then-MAC and AEAD modes provide robust authenticated encryption. File-system checksums and plaintext hashes do not provide cryptographic integrity." },
  { id:50419, domain:3, level:1, question:"What is the main weakness of relying solely on CRLs for revocation at scale?", options:["CRLs can grow large and be stale between periodic download intervals","CRLs cannot list more than a handful of revoked certificates total","CRLs reveal the private keys of all revoked certificates publicly","CRLs require a hardware security module on every client device in such deployments"], correct:0, explanation:"CRLs grow large and are only as current as the last download, creating staleness and bandwidth issues that OCSP and stapling help address." },
  { id:50420, domain:3, level:3, question:"In a VPN architecture, what does IKE Phase 1 establish?", options:["A secure authenticated channel and shared secret for negotiating further SAs","The bulk data encryption keys used to protect every user payload directly","The certificate revocation status of every participating VPN endpoint in most designs","The routing table entries used to forward traffic across the tunnel"], correct:0, explanation:"IKE Phase 1 sets up a secure, authenticated channel (ISAKMP SA); Phase 2 then negotiates the IPsec SAs that protect user traffic." },
  { id:50421, domain:3, level:2, question:"Why are pre-shared keys often considered weaker than certificates for VPN authentication at scale?", options:["Shared secrets are harder to manage, rotate, and isolate per endpoint at scale","Pre-shared keys cannot be used with any modern IPsec implementation in most designs","Certificates require no validation infrastructure while PSKs require a full PKI","Pre-shared keys provide non-repudiation that certificates cannot offer for this purpose"], correct:0, explanation:"PSKs are difficult to rotate and isolate per peer at scale and offer no per-identity assurance, whereas certificates scale better with a PKI." },
  { id:50422, domain:3, level:2, question:"What is the architectural benefit of using an authenticated key exchange like ECDHE in TLS?", options:["It eliminates the need for any symmetric encryption after the handshake","It provides forward secrecy and authenticates the exchange against tampering","It allows the server to reuse one static key for all sessions safely for this purpose","It removes the requirement for the server to present any certificate in practice"], correct:1, explanation:"ECDHE combined with certificate authentication gives forward secrecy and resists MITM. Symmetric encryption is still used for bulk data afterward." },
  { id:50423, domain:3, level:2, question:"Which best defines key derivation function (KDF) usage?", options:["Encrypting bulk data faster than a symmetric block cipher can across environments","Deriving one or more strong keys from a password or shared secret","Revoking compromised keys across a distributed certificate authority","Storing keys in plaintext for rapid retrieval by applications in this context"], correct:1, explanation:"A KDF derives cryptographically strong keys from passwords or shared secrets, often adding salt and work factor. It is not a bulk cipher." },
  { id:50424, domain:3, level:2, question:"Why is using a salt and high iteration count important in a password-based KDF?", options:["They make the derivation reversible so passwords can be recovered later","They shorten the derived key to fit into smaller storage fields in this scenario","They slow brute-force attempts and prevent precomputed table reuse","They allow the same password to derive the same key across all users"], correct:2, explanation:"Salt defeats precomputation and high iteration counts slow guessing. The derivation remains one-way and per-user salts ensure unique outputs." },
  { id:50425, domain:3, level:3, question:"An architect must protect a long-lived signing key used to sign firmware. Which control set is most appropriate?", options:["Store the key in application memory and rotate it every login session","Use an HSM with dual control, split knowledge, and strict access auditing","Embed the key in the firmware image so it travels with each device in such deployments","Email the key to release engineers to sign builds on demand quickly"], correct:1, explanation:"A high-value firmware-signing key warrants HSM protection with dual control, split knowledge, and auditing. Embedding or emailing it exposes it broadly." },
  { id:50426, domain:3, level:1, question:"What does the principle of algorithm independence in protocol design promote?", options:["Permanently binding a protocol to one specific algorithm forever as a general rule","Using a different protocol for each algorithm the system supports in such deployments","Removing all cryptography to avoid algorithm dependence entirely across environments","Allowing algorithms to be negotiated or replaced without protocol redesign"], correct:3, explanation:"Algorithm independence lets protocols negotiate or swap algorithms, supporting crypto-agility and future migration without redesigning the protocol." },
  { id:50427, domain:3, level:2, question:"Which is a correct statement about quantum key distribution (QKD)?", options:["It is a software algorithm that runs on ordinary classical computers","It uses quantum properties to detect eavesdropping during key exchange","It replaces the need for any authentication between the two endpoints","It encrypts bulk data faster than AES on quantum hardware platforms"], correct:1, explanation:"QKD leverages quantum mechanics so eavesdropping disturbs the channel detectably. It still requires authentication and does not itself bulk-encrypt data." },
  { id:50428, domain:3, level:1, question:"What is the security purpose of using authenticated encryption for stored backups?", options:["It ensures backups remain confidential and detects any tampering on restore","It compresses the backup so it occupies far less storage space by design","It removes the need to manage any keys for the backup system in this scenario","It guarantees the backup can be restored even without the key in this context"], correct:0, explanation:"Authenticated encryption keeps backups confidential and reveals tampering before restore. It still requires careful key management." },
  { id:50429, domain:3, level:3, question:"An architect notices a service decrypts data, processes it, then re-encrypts it, leaving plaintext briefly in memory. What is the best mitigation given constraints?", options:["Minimize plaintext lifetime, zeroize buffers, and consider memory protection or TEEs","Disable all logging so the plaintext is never written anywhere on disk in this scenario","Increase the encryption key length to compensate for the exposure window in this context","Accept the exposure because memory is inherently inaccessible to attackers in most designs"], correct:0, explanation:"Reducing plaintext residency, zeroizing buffers, and using protected memory or TEEs mitigate in-memory exposure. Key length does not address it." },
  { id:50430, domain:3, level:1, question:"What is the function of certificate revocation in the certificate lifecycle?", options:["To extend the certificate's validity period beyond its original expiry","To re-issue the certificate with a longer key automatically each year","To invalidate a certificate before its scheduled expiration date in such deployments","To encrypt the certificate so only the issuer can read its contents"], correct:2, explanation:"Revocation invalidates a certificate before expiry, for example after key compromise. It does not extend validity or re-issue keys." },
  { id:50431, domain:3, level:3, question:"Which revocation reason code scenario would prompt immediate certificate revocation?", options:["The corresponding private key is suspected of being compromised as a general rule","The certificate is approaching its normal scheduled expiration date soon","The organization changed its marketing logo on its public website","The certificate uses an algorithm the organization simply dislikes"], correct:0, explanation:"Key compromise warrants immediate revocation. Approaching expiry is handled by renewal, and cosmetic changes are not revocation triggers." },
  { id:50432, domain:3, level:3, question:"An architect must design encryption for a data lake queried by analytics. Which approach best balances security and analytic utility?", options:["Apply field-level encryption or tokenization to sensitive fields, leaving others usable","Encrypt the entire lake with one key and decrypt everything for each query under typical conditions","Store all data in plaintext since analytics requires readable values anyway for this purpose","Hash every field irreversibly so no analytics can ever read the values in practice as a general rule"], correct:0, explanation:"Selective field-level encryption or tokenization protects sensitive data while leaving non-sensitive fields available for analytics, balancing both needs." },
  { id:50433, domain:3, level:1, question:"What is the main risk of allowing weak or export-grade cipher suites for backward compatibility?", options:["They consume excessive bandwidth compared to modern strong cipher suites","They cause certificates to expire faster than normal validity periods","They prevent the server from presenting any certificate to clients","Attackers can force a downgrade and exploit the weakened cryptography"], correct:3, explanation:"Weak suites enable downgrade attacks where adversaries coerce use of breakable cryptography, so they should be disabled rather than retained." },
  { id:50434, domain:3, level:2, question:"Why is forward secrecy especially important for long-lived recorded encrypted traffic?", options:["It speeds up the handshake so more sessions can be recorded quickly for this purpose","It encrypts the certificate so the recorded traffic cannot be identified","It guarantees recorded traffic is automatically deleted after each session","Without it, future key compromise lets recorded sessions be decrypted later"], correct:3, explanation:"Without forward secrecy, an attacker who later obtains the server key can decrypt previously recorded sessions; PFS prevents this." },
  { id:50435, domain:3, level:1, question:"What does the term 'key ceremony' refer to in PKI operations?", options:["A formal, controlled procedure for generating and protecting critical keys","An informal meeting to discuss future encryption algorithm choices as a general rule","The automatic daily rotation of all end-entity certificate keys in such deployments","The public announcement that a certificate authority has been compromised"], correct:0, explanation:"A key ceremony is a formal, witnessed, controlled process for generating and securing high-value keys like a root CA key, often with dual control." },
  { id:50436, domain:3, level:2, question:"Why are root CA keys typically generated and used during a witnessed key ceremony?", options:["To ensure verifiable, controlled handling of the most critical trust anchor key","To make the root key publicly available to all relying parties quickly in such deployments","To allow the root to issue end-entity certificates faster than usual across environments","To avoid the need for any access control once the key is created by design in this scenario"], correct:0, explanation:"Witnessed ceremonies provide auditable, controlled generation/handling of the trust anchor, reducing insider risk and ensuring integrity of the root key." },
  { id:50437, domain:3, level:1, question:"What does the term 'key separation' (purpose binding) prevent?", options:["Using the same key for multiple purposes, which can enable cross-use attacks","Storing more than one key inside a single hardware security module across environments","Rotating keys on different schedules for different applications used by design","Backing up keys to more than one geographically separate location in this scenario"], correct:0, explanation:"Key separation binds each key to a single purpose, preventing attacks that exploit using one key across functions like signing and encryption." },
  { id:50438, domain:3, level:3, question:"An architect designs a system where auditors must verify signatures years later. Which key management practice is essential?", options:["Destroying the signing key immediately after each document is signed across environments","Preserving the signer's certificate and chain for long-term signature validation","Rotating the signing key hourly to limit any exposure window in this scenario","Encrypting all signed documents so auditors cannot read the contents in this context"], correct:1, explanation:"Long-term verification requires retaining the certificate, chain, and possibly timestamps so signatures remain validatable years later." },
  { id:50439, domain:3, level:2, question:"What is the role of a trusted timestamp authority in signature architectures?", options:["It encrypts the signed document to keep its contents confidential by design in this scenario","It generates the private key used by the signer for the signature in this scenario","It cryptographically attests when a signature or data existed at a point in time","It revokes the signer's certificate when the timestamp expires later in most designs"], correct:2, explanation:"A timestamp authority binds data to a time, proving a signature existed before key expiry or compromise, supporting long-term validation." },
  { id:50440, domain:3, level:2, question:"Which statement about symmetric key distribution using a key distribution center (KDC) is accurate?", options:["The KDC eliminates the need for any shared trust with the endpoints","The KDC is a trusted third party that issues session keys to parties","The KDC uses only asymmetric keys and never any symmetric keys in such deployments","Each endpoint must share its private signing key with the KDC directly"], correct:1, explanation:"A KDC is a trusted third party (as in Kerberos) that distributes symmetric session keys; endpoints share a long-term key with the KDC, not private signing keys." },
  { id:50441, domain:3, level:3, question:"In a Kerberos-style design, what is the main architectural risk concentrated in the KDC?", options:["The KDC cannot issue more than a few session keys before failing as a general rule","The KDC requires every client to hold an X.509 certificate first in such deployments","Compromise of the KDC undermines authentication for the entire realm","The KDC is unable to use any symmetric cryptography at all for this purpose"], correct:2, explanation:"The KDC is a single trust point; its compromise can forge tickets and undermine the whole realm's authentication, demanding strong protection." },
  { id:50442, domain:3, level:1, question:"What is the purpose of perfect forward secrecy in messaging applications like Signal?", options:["It ensures past messages stay secure even if current keys are compromised","It allows messages to be recovered if the long-term identity key leaks","It removes the need for any per-message ratcheting of session keys for this purpose","It encrypts only message metadata while leaving content in plaintext"], correct:0, explanation:"Forward secrecy via key ratcheting ensures compromise of a current key does not expose past messages, a core property of secure messaging." },
  { id:50443, domain:3, level:1, question:"What does post-compromise security (future secrecy) provide beyond forward secrecy?", options:["It recovers all plaintext messages after a device has been compromised under typical conditions","It restores confidentiality of future messages after a compromise via key updates","It prevents any key from ever being compromised in the first place in practice","It encrypts past messages retroactively once a compromise is detected as a general rule"], correct:1, explanation:"Post-compromise security heals future communications through ongoing key updates, whereas forward secrecy protects only past messages." },
  { id:50444, domain:3, level:2, question:"What is the architectural concern with storing encryption keys in the same database as the encrypted data?", options:["The database will run measurably slower with both keys and data present","An attacker who breaches the database obtains both keys and ciphertext","Keys stored in databases cannot be used by any cryptographic library","Encrypted data and keys cannot coexist in the same storage engine"], correct:1, explanation:"Co-locating keys with ciphertext means one breach yields both, defeating encryption. Keys belong in a separate KMS or HSM." },
  { id:50445, domain:3, level:3, question:"An architect must choose how to protect keys for an application running across many cloud instances. Which design best centralizes control?", options:["Generate a unique key on each instance with no central oversight in practice","Use a centralized KMS that issues, audits, and rotates keys for all instances","Embed identical keys in every instance image for consistency in such deployments","Store keys in environment variables visible in process listings across environments"], correct:1, explanation:"A centralized KMS provides consistent issuance, rotation, and auditing across instances. Per-instance ad hoc or embedded keys lack control and rotation." },
  { id:50446, domain:3, level:2, question:"Why is it risky to roll your own cryptographic algorithm or protocol?", options:["Custom algorithms are always slower than published standard algorithms","Standards bodies legally prohibit any custom cryptographic designs","They lack peer review and likely contain exploitable subtle weaknesses","Custom algorithms cannot be implemented in modern programming languages"], correct:2, explanation:"Unvetted custom crypto typically hides subtle flaws that public scrutiny of standard algorithms has eliminated; architects should use vetted standards." },
  { id:50447, domain:3, level:2, question:"What is the main purpose of a hardware root of trust in a platform's cryptographic architecture?", options:["To accelerate symmetric encryption for general application workloads","To store all application user passwords in an encrypted form securely","To provide a trusted foundation for measuring and verifying boot integrity","To replace the need for any operating-system-level access controls in this scenario"], correct:2, explanation:"A hardware root of trust (e.g., TPM) anchors measured boot and key protection, providing a trustworthy foundation for platform integrity verification." },
  { id:50448, domain:3, level:3, question:"How does a TPM contribute to disk encryption architectures?", options:["It encrypts the entire disk faster than the main CPU can manage across environments","It seals encryption keys to platform state so they release only if integrity holds","It stores the plaintext data alongside the keys for quick access later in this scenario","It replaces the disk controller to perform encryption in hardware directly in this context"], correct:1, explanation:"A TPM can seal keys to platform measurements, releasing them only if the boot state is unchanged, binding disk decryption to a trusted state." },
  { id:50449, domain:3, level:3, question:"An architect is told a vendor product encrypts data 'with proprietary unbreakable encryption.' What is the most appropriate response?", options:["Approve it immediately since proprietary algorithms are inherently stronger","Treat the claim skeptically and require use of vetted, standardized algorithms","Assume it is fine as long as the key length is at least 128 bits in this context","Require the vendor to keep the algorithm secret to maintain its strength"], correct:1, explanation:"Security through obscurity is unreliable; architects should require open, peer-reviewed standard algorithms (Kerckhoffs's principle) rather than secret proprietary ones." },
  { id:50450, domain:3, level:1, question:"What does Kerckhoffs's principle state about cryptographic system design?", options:["The algorithm must remain secret for the system to be considered secure","Keys should be as short as possible to maximize operational performance","Security should rest on the key's secrecy, not the algorithm's secrecy","Every system should use a unique secret algorithm known only to its owner"], correct:2, explanation:"Kerckhoffs's principle holds that a system should be secure even if the algorithm is public, relying only on the secrecy of the key." },
  { id:50451, domain:3, level:1, question:"What is a digital envelope in cryptography?", options:["A certificate wrapped inside another certificate for transport security in this context","A message encrypted symmetrically with the symmetric key encrypted asymmetrically","A plaintext message signed but deliberately left entirely unencrypted under typical conditions","A hash of a message stored separately from the message contents for this purpose"], correct:1, explanation:"A digital envelope encrypts the message with a symmetric key, then encrypts that key with the recipient's public key, combining speed and secure exchange." },
  { id:50452, domain:3, level:2, question:"Why is the recipient's public key used to encrypt the symmetric key in a digital envelope?", options:["So everyone on the network can decrypt the symmetric key easily in such deployments","So the sender retains the only ability to decrypt the message later","So the symmetric key never needs to be generated at all for this purpose","So only the recipient's private key can recover the symmetric key"], correct:3, explanation:"Encrypting the symmetric key with the recipient's public key ensures only the holder of the matching private key can recover and use it." },
  { id:50453, domain:3, level:2, question:"What is the architectural purpose of key blinding or hierarchical deterministic key derivation in some systems?", options:["To derive many keys from a master seed without storing each individually","To make all derived keys identical so management is greatly simplified","To eliminate the need for any randomness in the key generation process","To publish the master seed so others can derive the same keys too as a general rule"], correct:0, explanation:"Hierarchical derivation generates many keys from one seed, simplifying backup and management while keeping the seed secret and randomness intact." },
  { id:50454, domain:3, level:3, question:"An architect must support compliance requiring keys never leave a certified boundary, yet enable cloud encryption. Which design fits best?", options:["Export keys from the HSM to the cloud provider for convenience for this purpose","Store keys in the application configuration file within the cloud instance","Generate keys in software and email them to the cloud administrators","Use a FIPS-validated HSM or cloud HSM where keys never leave in plaintext"], correct:3, explanation:"A FIPS-validated HSM keeps keys within the certified boundary and never exposes them in plaintext, satisfying boundary requirements. Export or config storage violates them." },
  { id:50455, domain:3, level:1, question:"What is the risk of an excessively long cryptoperiod for a heavily used encryption key?", options:["The key becomes mathematically weaker the longer it exists unused in practice","More data is exposed if the key is compromised, and analysis material grows","The key automatically becomes a weak key after a fixed number of days","Long cryptoperiods make encryption operations progressively slower across environments"], correct:1, explanation:"A long cryptoperiod increases the volume of data at risk on compromise and gives cryptanalysts more material; rotation bounds this exposure." },
  { id:50456, domain:3, level:3, question:"Which best describes the architectural role of an OCSP responder?", options:["It issues new certificates to end entities upon enrollment requests","It stores the private keys of every certificate it reports on in such deployments","It provides signed real-time status answers about specific certificates","It encrypts traffic between the client and the certificate authority"], correct:2, explanation:"An OCSP responder returns signed status (good/revoked/unknown) for queried certificates in near real time. It does not issue certs or hold private keys." },
  { id:50457, domain:3, level:3, question:"A high-traffic site experiences OCSP responder latency affecting handshakes. Which architectural fix is most appropriate?", options:["Disable revocation checking entirely to remove the latency source","Enable OCSP stapling so the server provides a cached signed status","Switch every client to download full CRLs on each connection instead","Shorten all certificate validity periods to a single day to compensate"], correct:1, explanation:"OCSP stapling has the server fetch and present a cached signed status, removing per-client OCSP latency. Disabling revocation checking is insecure." },
  { id:50458, domain:3, level:3, question:"Why might an architect choose AES-256 over AES-128 for archival data?", options:["AES-256 encrypts data significantly faster than AES-128 in all cases","AES-128 cannot be used for data stored longer than one calendar year","AES-256 removes the need for any mode of operation or initialization vector","It provides a larger security margin against future and quantum advances"], correct:3, explanation:"AES-256 offers a larger margin for long-lived data, including against quantum Grover speedups. It is not faster and still needs a secure mode." },
  { id:50459, domain:3, level:2, question:"What is the architectural purpose of separating the certificate signing function onto an offline system?", options:["To keep the high-value signing key isolated from network-based attacks","To allow the signing system to issue certificates more rapidly to users","To eliminate the need for any backup of the certificate authority key","To let multiple administrators share the signing key without controls"], correct:0, explanation:"An offline (air-gapped) signing system isolates the critical key from network attacks, a best practice especially for root CAs." },
  { id:50460, domain:3, level:2, question:"Which describes the correct relationship between a public key and a private key?", options:["Both keys are identical and can be used interchangeably for any operation","The public key decrypts what the public key encrypted in a symmetric manner","Data encrypted with the public key is decrypted with the matching private key","The private key is shared publicly while the public key is kept secret"], correct:2, explanation:"In asymmetric crypto, the public and private keys are a mathematically linked pair; what one encrypts, only the other can decrypt. The private key stays secret." },
  { id:50461, domain:3, level:3, question:"An architect is reviewing a design that uses the same IV for every message in CTR mode with one key. What is the primary risk?", options:["The ciphertext will be far larger than necessary, wasting bandwidth","The encryption will simply fail and produce no output at all in most designs","The key will expire immediately after the first message is sent across environments","Keystream reuse lets an attacker recover plaintext via XOR relationships"], correct:3, explanation:"Reusing the IV/counter with the same key reproduces the keystream; XORing two ciphertexts cancels it and leaks plaintext, a critical CTR-mode flaw." },
  { id:50462, domain:3, level:1, question:"What does the term 'cryptographic binding' mean in the context of authenticated encryption?", options:["Permanently linking one encryption key to a single physical hardware device","Tying the ciphertext, authentication tag, and any associated data together","Joining two certificates so they expire on the same date together for this purpose","Binding a user's biometric template directly into the encryption key"], correct:1, explanation:"Cryptographic binding in AEAD ties ciphertext, tag, and associated data so tampering with any part is detected on decryption." },
  { id:50463, domain:3, level:2, question:"Why should random IVs or nonces be generated using a cryptographically secure source?", options:["Predictable IVs can enable attacks such as keystream reuse or chosen-plaintext","Random IVs make encryption operations run noticeably faster than fixed ones","IV randomness only affects file size and never affects security at all in practice","A weak IV source automatically strengthens the underlying cipher key as a general rule"], correct:0, explanation:"Predictable or repeating IVs/nonces undermine modes like CTR/GCM/CBC, enabling keystream reuse or chosen-plaintext attacks; secure randomness is essential." },
  { id:50464, domain:3, level:3, question:"An architect must design encryption for multi-region data replication with low latency. Which key strategy best balances security and availability?", options:["Use one global key only accessible from a single region's HSM for this purpose","Replicate keys securely across regional KMS or HSM clusters with access control","Generate a fresh unrelated key per request with no coordination at all as a general rule","Store the master key in each region's public object storage bucket in such deployments"], correct:1, explanation:"Securely replicating keys across regional KMS/HSM clusters provides low-latency access with control. A single-region key hurts availability; public storage is insecure." },
  { id:50465, domain:3, level:1, question:"What is the purpose of the Basic Constraints extension in an X.509 certificate?", options:["It lists the symmetric ciphers the certificate is permitted to negotiate","It stores the encrypted private key alongside the public certificate","It defines the geographic regions where the certificate may be used","It indicates whether the certificate may act as a CA and any path length"], correct:3, explanation:"Basic Constraints marks whether a cert is a CA and limits the certification path depth, preventing end-entity certs from acting as CAs." },
  { id:50466, domain:3, level:2, question:"Why is constraining path length via Basic Constraints important in a CA hierarchy?", options:["It speeds up TLS handshakes by shortening the certificate chain length","It encrypts intermediate certificates so attackers cannot read them","It prevents subordinate CAs from issuing further unauthorized sub-CAs","It allows end-entity certificates to issue their own child certificates"], correct:2, explanation:"Path length constraints limit how many subordinate CAs can exist below a CA, containing the scope of delegated issuance authority." },
  { id:50467, domain:3, level:2, question:"What is a primary architectural reason to use envelope encryption rather than encrypting all data directly with a KMS key?", options:["It allows the KMS master key to be stored in plaintext on disk safely","It removes the need to ever rotate the master key in the future","It encrypts data without requiring any data encryption key at all","It avoids sending large data volumes to the KMS for every operation"], correct:3, explanation:"Envelope encryption keeps bulk data local using DEKs while the KMS only protects the small KEK, avoiding sending large data through the KMS." },
  { id:50468, domain:3, level:3, question:"An architect must enable a vendor to process encrypted records and return aggregate statistics without seeing raw data. Which technology is most fitting?", options:["Homomorphic encryption allowing computation on the ciphertext directly","Transport Layer Security between the architect and the vendor systems","Full-disk encryption on the vendor's processing servers and databases","A certificate revocation list shared between both organizations involved"], correct:0, explanation:"Homomorphic encryption lets the vendor compute on ciphertext and return encrypted results without seeing plaintext, unlike transport or disk encryption." },
  { id:50469, domain:3, level:1, question:"What does the term 'crypto-agility debt' describe in long-lived systems?", options:["The financial cost of purchasing additional hardware security modules by design","Accumulated hard-coded cryptographic choices that are costly to change later","The interest paid on loans used to acquire encryption software licenses","The delay introduced by encryption on every network transaction processed"], correct:1, explanation:"Crypto-agility debt is the accumulated difficulty of changing entrenched, hard-coded cryptographic choices, making future migration expensive and risky." },
  { id:50470, domain:3, level:3, question:"Which is a sound architectural reason to prefer standardized AEAD ciphers in new protocols?", options:["They are the only ciphers that can ever be implemented in software in this scenario","They eliminate the need to manage or rotate any encryption keys in this context","They reduce composition mistakes by combining encryption and authentication","They guarantee immunity to every possible cryptographic attack ever"], correct:2, explanation:"AEAD ciphers integrate confidentiality and integrity, reducing the error-prone manual composition of encryption and MAC. No cipher is universally immune." },
  { id:50471, domain:3, level:1, question:"What is the function of a certificate's thumbprint or fingerprint?", options:["The encrypted private key embedded for backup and recovery use as a general rule","The list of all domains the certificate is authorized to secure in such deployments","The symmetric session key negotiated during the TLS handshake across environments","A hash of the certificate used to identify and pin it reliably by design"], correct:3, explanation:"A fingerprint is a hash of the certificate used to identify or pin it. It does not contain private keys, domain lists, or session keys." },
  { id:50472, domain:3, level:3, question:"An architect designs certificate pinning but worries about operational risk. What is the main downside to plan for?", options:["Pinning makes the TLS handshake impossible to complete successfully in most designs","Pinning prevents the server from using forward secrecy in any session under typical conditions","A pinned certificate or key rotation can break clients if not managed carefully","Pinning forces all clients to disable certificate validation entirely in practice"], correct:2, explanation:"Pinning can cause outages when certs/keys rotate unless backup pins and update strategies are planned. It does not break forward secrecy." },
  { id:50473, domain:3, level:2, question:"Why is it important to validate the full certificate chain rather than just the leaf certificate?", options:["The leaf certificate contains the trusted root's private signing key","Only the leaf certificate ever expires, so the chain is irrelevant for this purpose","Chain validation encrypts the connection that the leaf cannot encrypt in practice","Trust derives from a chain up to a trusted anchor, so each link must validate"], correct:3, explanation:"Trust flows from a trusted root through intermediates to the leaf; validating only the leaf misses revoked or untrusted issuers in the chain." },
  { id:50474, domain:3, level:2, question:"What is the purpose of HSTS in a web security architecture relating to cryptography?", options:["It encrypts cookies stored in the browser using a server-supplied key","It replaces the TLS certificate with a self-signed certificate automatically","It forces browsers to use HTTPS, preventing protocol downgrade to HTTP","It generates the symmetric session keys used during the TLS handshake"], correct:2, explanation:"HSTS instructs browsers to only use HTTPS for a domain, preventing SSL-stripping downgrades to plaintext HTTP. It does not handle key generation." },
  { id:50475, domain:3, level:3, question:"An architect must protect API secrets used by ephemeral serverless functions. Which approach is most secure?", options:["Fetch secrets at runtime from a secrets manager using short-lived identity","Embed the secrets in the deployment package shipped to every function","Store the secrets in environment variables committed to the code repository","Hard-code the secrets and rotate the entire codebase whenever they change"], correct:0, explanation:"Fetching secrets at runtime via a managed secrets store with short-lived workload identity avoids embedding secrets in code or images, easing rotation." },
  { id:50476, domain:3, level:1, question:"What does 'least privilege' mean applied to cryptographic key access?", options:["Every administrator should have access to all keys for redundancy","Only entities that need a key for a function are granted access to it","Keys should be accessible to anyone to ensure operational availability","All keys should be exportable so they can be used anywhere needed"], correct:1, explanation:"Least privilege limits key access to only those entities and operations that require it, reducing exposure and misuse risk." },
  { id:50477, domain:3, level:3, question:"Which best describes the role of a master key in a key hierarchy?", options:["It directly encrypts all application data without any intermediate keys","It protects subordinate keys and is itself highly guarded and rarely used","It is distributed to every endpoint so they can decrypt data locally","It is rotated on every transaction to maximize cryptographic strength"], correct:1, explanation:"A master key (KEK) protects subordinate data keys and is tightly controlled and seldom exposed, rather than directly encrypting bulk data everywhere." },
  { id:50478, domain:3, level:3, question:"An architect must justify rotating a master key that protects thousands of wrapped data keys. What is the efficient approach?", options:["Decrypt and re-encrypt every data record under a brand-new master key","Discard all existing data because the master key changed entirely by design","Re-wrap the data keys under the new master key without touching the data","Generate a new master key but keep wrapping with the old one anyway"], correct:2, explanation:"In envelope encryption, rotating the master key only requires re-wrapping the data keys, not re-encrypting all the underlying data, which is efficient." },
  { id:50479, domain:3, level:2, question:"What is the architectural significance of FIPS 140-3 superseding FIPS 140-2?", options:["It removes all requirements for cryptographic module validation entirely","It mandates that all modules be implemented purely in software only","It aligns the validation standard with international ISO/IEC requirements","It eliminates the concept of security levels from module validation"], correct:2, explanation:"FIPS 140-3 aligns with ISO/IEC 19790 and 24759, modernizing the validation program while retaining the concept of security levels." },
  { id:50480, domain:3, level:2, question:"Why is separating duties between key custodians and security officers recommended in HSM operations?", options:["It allows a single person to manage all key and policy functions alone in this scenario","It removes the need for any authentication to the hardware security module in this context","It prevents any one role from both controlling keys and the policies governing them","It guarantees the HSM never needs firmware updates or maintenance again under typical conditions"], correct:2, explanation:"Separating custodial and administrative roles prevents a single individual from both holding keys and setting the policies, reducing insider risk." },
  { id:50481, domain:3, level:1, question:"What is the main reason to avoid using MD5 in any security-sensitive context today?", options:["MD5 outputs are too long to store in modern database schema fields in this context","MD5 is a symmetric cipher unsuitable for producing message digests in most designs","MD5 is broken with practical collision attacks undermining its integrity use","MD5 requires specialized hardware that is no longer produced anywhere for this purpose"], correct:2, explanation:"MD5 has practical collision attacks, making it unsafe for integrity or signatures. It is a hash function, not a symmetric cipher." },
  { id:50482, domain:3, level:3, question:"An architect is asked to add encryption to a legacy system that cannot change its data field sizes. Which technique fits the constraint best?", options:["Standard AES-CBC encryption that expands data to block-aligned sizes","RSA encryption applied directly to each individual data field value","SHA-256 hashing applied to every field to obscure the values stored","Format-preserving encryption that retains the original length and format"], correct:3, explanation:"FPE keeps ciphertext the same length and format as plaintext, fitting fixed legacy fields. CBC expands data and hashing is irreversible." },
  { id:50483, domain:3, level:1, question:"What does the term 'key agreement' refer to, as distinct from 'key transport'?", options:["One party generates the key and sends it encrypted to the other party","A central authority dictates the key both parties must use without input","The key is agreed verbally between administrators before any session in practice","Both parties jointly contribute to deriving a shared key, as in Diffie-Hellman"], correct:3, explanation:"Key agreement (e.g., DH) has both parties contribute to the shared key; key transport has one party generate and send the key to the other." },
  { id:50484, domain:3, level:2, question:"Why might static keys be inferior to ephemeral keys for session security?", options:["Static keys make handshakes slower and consume far more bandwidth for this purpose","Ephemeral keys cannot authenticate the parties involved in any way in practice","Static keys must always be longer than ephemeral keys to be valid as a general rule","Compromise of a static key can expose many sessions lacking forward secrecy"], correct:3, explanation:"A compromised static key can decrypt all sessions it secured, lacking forward secrecy, whereas ephemeral keys limit exposure to a single session." },
  { id:50485, domain:3, level:3, question:"An architect plans algorithm migration and must avoid breaking existing data. Which approach allows gradual transition?", options:["Tag stored data with its algorithm so old and new can coexist during migration","Immediately delete all data encrypted with the old algorithm at once as a general rule","Force every client to upgrade simultaneously with no transition window in such deployments","Re-encrypt nothing and simply hope the old algorithm stays secure across environments"], correct:0, explanation:"Tagging data with its algorithm/key version lets old and new coexist, enabling lazy or phased re-encryption without breaking access during migration." },
  { id:50486, domain:3, level:1, question:"What is the purpose of a counter or sequence number in protocols like IPsec ESP?", options:["To encrypt the payload faster than a block cipher otherwise could as a general rule","To store the negotiated symmetric session key inside each packet header in such deployments","To indicate which certificate authority issued the endpoint's certificate across environments","To provide anti-replay protection by detecting duplicate or out-of-order packets"], correct:3, explanation:"Sequence numbers enable anti-replay by detecting duplicated or replayed packets within the security association window." },
  { id:50487, domain:3, level:3, question:"Which statement about key length and security is most accurate for an architect?", options:["Longer keys always make every algorithm proportionally more secure forever","Key length is irrelevant as long as a standard algorithm is being used","Symmetric and asymmetric keys of equal bit length offer equal strength","Appropriate key length depends on the algorithm and threat model considered"], correct:3, explanation:"Adequate key length depends on the algorithm and threats; notably, symmetric and asymmetric keys of equal bit length differ greatly in strength." },
  { id:50488, domain:3, level:2, question:"Why do symmetric and asymmetric keys of the same bit length differ in security strength?", options:["Symmetric keys are weaker because they are shared between two parties across environments","They are actually identical in strength at equal bit lengths always by design","Asymmetric keys are stronger only because they are kept fully secret in this scenario","Asymmetric security depends on hard math problems, not pure brute force of bits"], correct:3, explanation:"Asymmetric strength relies on problems like factoring/discrete log, so a 2048-bit RSA key is far weaker bit-for-bit than a 256-bit symmetric key." },
  { id:50489, domain:3, level:3, question:"An architect must design encryption for a system subject to lawful key disclosure orders in one jurisdiction but not another. Which approach best preserves customer control?", options:["Store all keys with the cloud provider in the disclosing jurisdiction","Embed keys in client applications so no central party holds them at all","Use Hold Your Own Key so the customer alone controls disclosure decisions","Escrow all keys with the provider for operational convenience and speed"], correct:2, explanation:"HYOK keeps key control with the customer, so disclosure requests must go to them rather than the provider, preserving control across jurisdictions." },
  { id:50490, domain:3, level:2, question:"What is the architectural benefit of using authenticated encryption for inter-service messages on a network?", options:["It protects both confidentiality and integrity, detecting tampering in transit","It compresses the messages to reduce overall network bandwidth usage in this context","It removes the need for any transport-layer security between the services","It guarantees the messages are delivered exactly once without duplication"], correct:0, explanation:"Authenticated encryption secures confidentiality and detects tampering of messages in transit. It does not handle compression or delivery guarantees." },
  { id:50491, domain:3, level:3, question:"Why should an architect avoid using a single shared key across an entire fleet of devices?", options:["Compromise of one device exposes the key and thus the entire fleet","A single key cannot technically be loaded onto more than one device","Shared keys cause devices to encrypt data more slowly over time across environments","A shared key prevents devices from communicating with each other by design"], correct:0, explanation:"One shared key means a single device compromise exposes all devices; per-device keys contain the blast radius of any single compromise." },
  { id:50492, domain:3, level:2, question:"An architect must design key generation for millions of IoT devices at manufacture. Which approach best balances scale and security?", options:["Burn the same factory key into every device for simple provisioning","Generate unique per-device keys provisioned securely during manufacturing","Let each device pick its own key from a tiny fixed list of values for this purpose","Defer key generation until each device first connects over plaintext"], correct:1, explanation:"Unique per-device keys provisioned securely at manufacture contain compromise to one device. A shared factory key or tiny key space is dangerous." },
  { id:50493, domain:3, level:2, question:"What is the architectural value of using standardized key wrapping algorithms (e.g., AES Key Wrap)?", options:["They securely protect keys with integrity, vetted for the key-wrapping use case","They allow data keys to be stored in plaintext without any protection for this purpose","They eliminate the need for any master or key-encryption key entirely in practice","They make wrapped keys readable by any system without the wrapping key as a general rule"], correct:0, explanation:"Standardized key wrap algorithms protect key confidentiality and integrity and are vetted specifically for wrapping keys, unlike ad hoc encryption." },
  { id:50494, domain:3, level:1, question:"Which describes a downgrade attack mitigation built into TLS 1.3?", options:["It permits negotiation down to SSL 3.0 for maximum client compatibility","It disables certificate validation to simplify the handshake process in practice","It encrypts the negotiated version so attackers cannot influence it at all","It removes obsolete ciphers and adds mechanisms signaling downgrade attempts"], correct:3, explanation:"TLS 1.3 removed weak ciphers and includes downgrade-detection signaling in the handshake to resist forced fallback to weaker versions." },
  { id:50495, domain:3, level:2, question:"An architect reviews a system that authenticates messages with a MAC but the verification compares tags using a non-constant-time string compare. What is the risk?", options:["The MAC will fail to authenticate any legitimate messages at all in practice","The comparison will run too slowly to be usable in production systems","The MAC key length will effectively be halved by the comparison method","A timing side channel may let an attacker forge a valid tag incrementally"], correct:3, explanation:"Non-constant-time tag comparison leaks via timing how many bytes matched, enabling incremental forgery; constant-time comparison mitigates it." },
  { id:50496, domain:3, level:1, question:"What is the purpose of associating a key identifier (key ID) with ciphertext?", options:["To allow the correct key to be located for decryption and rotation","To store the plaintext value alongside the ciphertext for fast access","To make the ciphertext readable without needing the key at all","To indicate which user is permitted to read the plaintext data for this purpose"], correct:0, explanation:"A key ID lets the system find the right key version for decryption and supports rotation by distinguishing which key encrypted given ciphertext." },
  { id:50497, domain:3, level:2, question:"An architect must choose a strategy so that compromise of a current TLS server key does not expose years of recorded sessions. Which is essential?", options:["Mandate ephemeral key exchange (ECDHE) to provide perfect forward secrecy","Use the longest possible RSA key for static key exchange operations","Reuse one session key across all connections to simplify the design","Disable certificate validation to speed up each handshake significantly"], correct:0, explanation:"Ephemeral key exchange provides forward secrecy so a later server-key compromise cannot decrypt recorded sessions. Static RSA key exchange lacks this property." },
  { id:50498, domain:3, level:3, question:"An architect must design a crypto governance program. Which element is most foundational?", options:["A list of preferred vendors regardless of their cryptographic capabilities","A single annual meeting to informally discuss encryption preferences by design","A documented standard defining approved algorithms, key lengths, and lifecycles","A policy delegating all cryptographic decisions to individual developers in this context"], correct:2, explanation:"A foundational crypto governance program defines approved algorithms, key lengths, and lifecycle requirements, guided by standards like NIST SP 800-57." },
  { id:50499, domain:3, level:2, question:"Why is inventorying cryptographic assets important before a post-quantum migration?", options:["It allows the organization to delete all encryption immediately and safely","You cannot migrate or prioritize what you have not identified and located","Inventory automatically converts all algorithms to quantum-safe versions","It removes the need to test any of the new post-quantum algorithms first"], correct:1, explanation:"A cryptographic inventory reveals where vulnerable algorithms and keys live so migration can be prioritized; you cannot remediate what you have not located." },
  { id:50500, domain:3, level:2, question:"What is the architectural rationale for combining tokenization for storage with encryption for transit in a payment system?", options:["Tokenization protects stored card data scope while encryption secures data moving between systems","Both perform the same function so the combination is purely redundant overhead in this context","Encryption removes stored data from scope while tokenization secures the network path in most designs","Tokenization secures the network while encryption replaces the stored card data with tokens"], correct:0, explanation:"Tokenization removes stored card data from scope while transit encryption protects data moving across the network, addressing storage and transmission risks respectively." }
];
if (typeof window !== 'undefined') window.QUESTIONS_ISSAP_C2 = QUESTIONS_ISSAP_C2;
